import redis
from rediscluster import RedisCluster

# Configuration for Redis cluster
startup_nodes = [
    {"host": "redis-node-1", "port": "6379"},
    {"host": "redis-node-2", "port": "6379"},
    {"host": "redis-node-3", "port": "6379"}
]

# Connect to Redis cluster
rc = RedisCluster(startup_nodes=startup_nodes, decode_responses=True)

def store_user_data(user_id, session_token, api_key):
    # Set session token with TTL (e.g., 1 hour)
    rc.setex(f"session:{user_id}", 3600, session_token)
    
    # Set API key with TTL (e.g., 24 hours)
    rc.setex(f"api_key:{user_id}", 86400, api_key)

def get_user_data(user_id):
    session_token = rc.get(f"session:{user_id}")
    api_key = rc.get(f"api_key:{user_id}")
    return session_token, api_key

# Example usage
if __name__ == "__main__":
    user_id = "example_user"
    session_token = "secure_session_token"
    api_key = "secure_api_key"
    
    # Store user data
    store_user_data(user_id, session_token, api_key)
    
    # Retrieve user data
    stored_session_token, stored_api_key = get_user_data(user_id)
    print(f"Session Token: {stored_session_token}")
    print(f"API Key: {stored_api_key}")